-- ============================================================
-- RECETAS COMPLETAS: Perfumes terminados BOM (Bill of Materials)
-- Tenant: d46bec36-5259-4b5b-83c7-01f1e6ea5dcd (Perfum Mua)
-- Sede 1: 239 extractos  |  Sede 2: 351 extractos
-- Total: 590 extractos x 3 presentaciones = 1770 productos terminados
-- 5310 registros de recetas (3 ingredientes x 3 tamanos)
-- Ejecutar: mysql -u root -p stockpro_db < recetasperfummua.sql
-- NOTA: Archivo auto-contenido — no requiere ejecutar inventario_perfummua.sql primero
-- ============================================================

USE stockpro_db;

SET FOREIGN_KEY_CHECKS = 0;
SET UNIQUE_CHECKS = 0;
SET SQL_MODE = '';

-- ============================================================
-- 1. TABLA DE RECETAS
-- ============================================================
CREATE TABLE IF NOT EXISTS product_recipes (
    id VARCHAR(36) PRIMARY KEY,
    tenant_id VARCHAR(36) NOT NULL,
    product_id VARCHAR(36) NOT NULL,
    ingredient_id VARCHAR(36) NOT NULL,
    quantity DECIMAL(10,3) NOT NULL,
    include_in_cost TINYINT(1) NOT NULL DEFAULT 1,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE,
    FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
    FOREIGN KEY (ingredient_id) REFERENCES products(id) ON DELETE RESTRICT,
    INDEX idx_recipe_product (product_id),
    INDEX idx_recipe_tenant (tenant_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Agregar columna include_in_cost si la tabla ya existía sin ella
DROP PROCEDURE IF EXISTS _pm_add_col;
DELIMITER //
CREATE PROCEDURE _pm_add_col()
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE()
          AND TABLE_NAME   = 'product_recipes'
          AND COLUMN_NAME  = 'include_in_cost'
    ) THEN
        ALTER TABLE product_recipes
            ADD COLUMN include_in_cost TINYINT(1) NOT NULL DEFAULT 1;
    END IF;
END //
DELIMITER ;
CALL _pm_add_col();
DROP PROCEDURE IF EXISTS _pm_add_col;

-- ============================================================
-- 2. VARIABLES
-- ============================================================
SET @tid    = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd' COLLATE utf8mb4_unicode_ci;
SET @env30  = 'prod-pm-2002' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 30ML  ($2,738)
SET @env100 = 'prod-pm-2004' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 100ML ($2,847)
SET @caj30  = 'prod-pm-2005' COLLATE utf8mb4_unicode_ci; -- CAJA 30-50ML         ($1,800)
SET @caj100 = 'prod-pm-2006' COLLATE utf8mb4_unicode_ci; -- CAJA 100ML           ($1,600)
SET @env50  = 'prod-pm-2007' COLLATE utf8mb4_unicode_ci; -- ENVASE LACOSTE 50ML  ($2,808)

-- ============================================================
