-- ============================================================
-- 4. LIMPIAR DATOS PREVIOS (idempotente)
-- ============================================================
DELETE FROM product_recipes WHERE tenant_id = @tid AND product_id LIKE 'PERF-%';
DELETE FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-s1-%';
DELETE FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-s2-%';

-- ============================================================
-- 5. INSUMOS: CAJAS Y ENVASES
-- ============================================================




-- ============================================================
-- 5b. EXTRACTOS (ingredientes activos de los perfumes)
--     589 extractos: 238 sede 1 + 351 sede 2
-- ============================================================
DELETE FROM products WHERE tenant_id = @tid AND id REGEXP '^prod-pm-s[12]-[0-9]+$';




